import React, { useState, useEffect } from 'react';
import ExpenseService from '../services/ExpenseService';

const Dashboard = () => {
    const [expenses, setExpenses] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchExpenses();
    }, []);

    const fetchExpenses = async () => {
        try {
            const response = await ExpenseService.getAllExpenses();
            setExpenses(response.data);
        } catch (error) {
            console.error('Error fetching expenses:', error);
        } finally {
            setLoading(false);
        }
    };

    const totalAmount = expenses.reduce((sum, e) => sum + (e.amount || 0), 0);

    const byProject = expenses.reduce((acc, e) => {
        acc[e.projectName] = (acc[e.projectName] || 0) + e.amount;
        return acc;
    }, {});

    const byType = expenses.reduce((acc, e) => {
        acc[e.expenseType] = (acc[e.expenseType] || 0) + e.amount;
        return acc;
    }, {});

    const recentExpenses = [...expenses]
        .sort((a, b) => new Date(b.date) - new Date(a.date))
        .slice(0, 5);

    if (loading) return <div className="loading">Loading dashboard...</div>;

    return (
        <div className="dashboard">
            <h2 className="page-title">📊 Dashboard</h2>

            {/* Summary Cards */}
            <div className="stats-grid">
                <div className="stat-card primary">
                    <div className="stat-icon">💰</div>
                    <div className="stat-info">
                        <h3>Total Expenses</h3>
                        <p className="stat-value">₹{totalAmount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</p>
                    </div>
                </div>
                <div className="stat-card info">
                    <div className="stat-icon">📋</div>
                    <div className="stat-info">
                        <h3>Total Records</h3>
                        <p className="stat-value">{expenses.length}</p>
                    </div>
                </div>
                <div className="stat-card success">
                    <div className="stat-icon">🏗️</div>
                    <div className="stat-info">
                        <h3>Active Projects</h3>
                        <p className="stat-value">{Object.keys(byProject).length}</p>
                    </div>
                </div>
                <div className="stat-card warning">
                    <div className="stat-icon">📦</div>
                    <div className="stat-info">
                        <h3>Expense Types</h3>
                        <p className="stat-value">{Object.keys(byType).length}</p>
                    </div>
                </div>
            </div>

            <div className="dashboard-grid">
                {/* Project Breakdown */}
                <div className="dashboard-card">
                    <h3>💼 Expenses by Project</h3>
                    {Object.keys(byProject).length === 0 ? (
                        <p className="no-data">No project data available.</p>
                    ) : (
                        <table className="breakdown-table">
                            <thead>
                                <tr>
                                    <th>Project Name</th>
                                    <th>Total Amount</th>
                                </tr>
                            </thead>
                            <tbody>
                                {Object.entries(byProject).map(([project, amount]) => (
                                    <tr key={project}>
                                        <td>{project}</td>
                                        <td className="amount-cell">₹{amount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>

                {/* Expense Type Breakdown */}
                <div className="dashboard-card">
                    <h3>🏷️ Expenses by Type</h3>
                    {Object.keys(byType).length === 0 ? (
                        <p className="no-data">No expense type data available.</p>
                    ) : (
                        <table className="breakdown-table">
                            <thead>
                                <tr>
                                    <th>Expense Type</th>
                                    <th>Total Amount</th>
                                </tr>
                            </thead>
                            <tbody>
                                {Object.entries(byType).map(([type, amount]) => (
                                    <tr key={type}>
                                        <td>{type}</td>
                                        <td className="amount-cell">₹{amount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
            </div>

            {/* Recent Expenses */}
            <div className="dashboard-card full-width">
                <h3>🕒 Recent Expenses</h3>
                {recentExpenses.length === 0 ? (
                    <p className="no-data">No recent expenses.</p>
                ) : (
                    <table className="breakdown-table">
                        <thead>
                            <tr>
                                <th>Project</th>
                                <th>Type</th>
                                <th>Vendor</th>
                                <th>Date</th>
                                <th>Amount</th>
                            </tr>
                        </thead>
                        <tbody>
                            {recentExpenses.map(expense => (
                                <tr key={expense.id}>
                                    <td>{expense.projectName}</td>
                                    <td><span className="badge">{expense.expenseType}</span></td>
                                    <td>{expense.vendor}</td>
                                    <td>{expense.date}</td>
                                    <td className="amount-cell">₹{expense.amount.toLocaleString('en-IN', { minimumFractionDigits: 2 })}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

export default Dashboard;
